+    let dispatcher;
+    try {
+      dispatcher = createBrowserRouteDispatcher(createBrowserControlContext());
+    } catch (err) {
+      respond(false, undefined, errorShape(ErrorCodes.UNAVAILABLE, String(err)));
+      return;
+    }
+
+    const result = await dispatcher.dispatch({
+      method: methodRaw,
+      path,
+      query,
+      body,
+    });
+
+    if (result.status >= 400) {
